-- Parameterized Stored Procedure to aggregate monthly claim performance metrics
CREATE PROCEDURE dbo.sp_GetClaimsMetricsByPeriod
  @StartDate DATE,
  @EndDate DATE,
  @MinSettlementAmount DECIMAL(18,2) = 0.00
AS
BEGIN
  SET NOCOUNT ON;

  BEGIN TRY
    -- Validate dates
    IF @StartDate > @EndDate
    BEGIN
      RAISERROR('Start date cannot be greater than end date.', 16, 1);
      RETURN;
    END

    -- Retrieve aggregated records
    SELECT 
      p.ProductLine,
      COUNT(c.ClaimID) AS TotalClaims,
      SUM(c.ClaimAmount) AS AggregateClaimAmount,
      AVG(DATEDIFF(day, c.ReportedDate, c.SettledDate)) AS AvgSettlementDays,
      SUM(CASE WHEN DATEDIFF(day, c.ReportedDate, c.SettledDate) > 30 THEN 1 ELSE 0 END) AS SLABreachCount
    FROM dbo.FactClaims c
    INNER JOIN dbo.DimPolicy p ON c.PolicyID = p.PolicyID
    WHERE c.ReportedDate BETWEEN @StartDate AND @EndDate
      AND c.ClaimAmount >= @MinSettlementAmount
    GROUP BY p.ProductLine
    ORDER BY AggregateClaimAmount DESC;

  END TRY
  BEGIN CATCH
    -- Error handling
    DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
    DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
    DECLARE @ErrorState INT = ERROR_STATE();

    RAISERROR(@ErrorMessage, @ErrorSeverity, @ErrorState);
  END CATCH
END;
GO
